2550 void VPVectorEndPointerRecipe::execute(VPTransformState &State) {
2551   auto &Builder = State.Builder;
2552   unsigned CurrentPart = getUnrollPart(*this);
2553   const DataLayout &DL = Builder.GetInsertBlock()->getDataLayout();
2554   Type *IndexTy = DL.getIndexType(State.TypeAnalysis.inferScalarType(this));
2555 
2556   // The wide store needs to start at the last vector element.
2557   Value *RunTimeVF = State.get(getVFValue(), VPLane(0));
2558   if (IndexTy != RunTimeVF->getType())
2559     RunTimeVF = Builder.CreateZExtOrTrunc(RunTimeVF, IndexTy);
2560   // NumElt = Stride * CurrentPart * RunTimeVF
2561   Value *NumElt = Builder.CreateMul(
2562       ConstantInt::getSigned(IndexTy, Stride * (int64_t)CurrentPart),
2563       RunTimeVF);
2564   // LastLane = Stride * (RunTimeVF - 1)
2565   Value *LastLane = Builder.CreateSub(RunTimeVF, ConstantInt::get(IndexTy, 1));
2566   if (Stride != 1)
2567     LastLane =
2568         Builder.CreateMul(ConstantInt::getSigned(IndexTy, Stride), LastLane);
2569   Value *Ptr = State.get(getOperand(0), VPLane(0));
2570   Value *ResultPtr =
2571       Builder.CreateGEP(IndexedTy, Ptr, NumElt, "", getGEPNoWrapFlags());
2572   ResultPtr = Builder.CreateGEP(IndexedTy, ResultPtr, LastLane, "",
2573                                 getGEPNoWrapFlags());
2574 
2575   State.set(this, ResultPtr, /*IsScalar*/ true);
2576 }
