2649 void VPReductionRecipe::execute(VPTransformState &State) {
2650   assert(!State.Lane && "Reduction being replicated.");
2651   RecurKind Kind = getRecurrenceKind();
2652   assert(!RecurrenceDescriptor::isAnyOfRecurrenceKind(Kind) &&
2653          "In-loop AnyOf reductions aren't currently supported");
2654   // Propagate the fast-math flags carried by the underlying instruction.
2655   IRBuilderBase::FastMathFlagGuard FMFGuard(State.Builder);
2656   State.Builder.setFastMathFlags(getFastMathFlags());
2657   Value *NewVecOp = State.get(getVecOp());
2658   if (VPValue *Cond = getCondOp()) {
2659     Value *NewCond = State.get(Cond, State.VF.isScalar());
2660     VectorType *VecTy = dyn_cast<VectorType>(NewVecOp->getType());
2661     Type *ElementTy = VecTy ? VecTy->getElementType() : NewVecOp->getType();
2662 
2663     Value *Start = getRecurrenceIdentity(Kind, ElementTy, getFastMathFlags());
2664     if (State.VF.isVector())
2665       Start = State.Builder.CreateVectorSplat(VecTy->getElementCount(), Start);
2666 
2667     Value *Select = State.Builder.CreateSelect(NewCond, NewVecOp, Start);
2668     NewVecOp = Select;
2669   }
2670   Value *NewRed;
2671   Value *NextInChain;
2672   if (isOrdered()) {
2673     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ true);
2674     if (State.VF.isVector())
2675       NewRed =
2676           createOrderedReduction(State.Builder, Kind, NewVecOp, PrevInChain);
2677     else
2678       NewRed = State.Builder.CreateBinOp(
2679           (Instruction::BinaryOps)RecurrenceDescriptor::getOpcode(Kind),
2680           PrevInChain, NewVecOp);
2681     PrevInChain = NewRed;
2682     NextInChain = NewRed;
2683   } else if (isPartialReduction()) {
2684     assert(Kind == RecurKind::Add && "Unexpected partial reduction kind");
2685     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ false);
2686     NewRed = State.Builder.CreateIntrinsic(
2687         PrevInChain->getType(), Intrinsic::vector_partial_reduce_add,
2688         {PrevInChain, NewVecOp}, nullptr, "partial.reduce");
2689     PrevInChain = NewRed;
2690     NextInChain = NewRed;
2691   } else {
2692     assert(isInLoop() &&
2693            "The reduction must either be ordered, partial or in-loop");
2694     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ true);
2695     NewRed = createSimpleReduction(State.Builder, NewVecOp, Kind);
2696     if (RecurrenceDescriptor::isMinMaxRecurrenceKind(Kind))
2697       NextInChain = createMinMaxOp(State.Builder, Kind, NewRed, PrevInChain);
2698     else
2699       NextInChain = State.Builder.CreateBinOp(
2700           (Instruction::BinaryOps)RecurrenceDescriptor::getOpcode(Kind),
2701           PrevInChain, NewRed);
2702   }
2703   State.set(this, NextInChain, /*IsScalar*/ !isPartialReduction());
2704 }
