2706 void VPReductionEVLRecipe::execute(VPTransformState &State) {
2707   assert(!State.Lane && "Reduction being replicated.");
2708 
2709   auto &Builder = State.Builder;
2710   // Propagate the fast-math flags carried by the underlying instruction.
2711   IRBuilderBase::FastMathFlagGuard FMFGuard(Builder);
2712   Builder.setFastMathFlags(getFastMathFlags());
2713 
2714   RecurKind Kind = getRecurrenceKind();
2715   Value *Prev = State.get(getChainOp(), /*IsScalar*/ true);
2716   Value *VecOp = State.get(getVecOp());
2717   Value *EVL = State.get(getEVL(), VPLane(0));
2718 
2719   Value *Mask;
2720   if (VPValue *CondOp = getCondOp())
2721     Mask = State.get(CondOp);
2722   else
2723     Mask = Builder.CreateVectorSplat(State.VF, Builder.getTrue());
2724 
2725   Value *NewRed;
2726   if (isOrdered()) {
2727     NewRed = createOrderedReduction(Builder, Kind, VecOp, Prev, Mask, EVL);
2728   } else {
2729     NewRed = createSimpleReduction(Builder, VecOp, Kind, Mask, EVL);
2730     if (RecurrenceDescriptor::isMinMaxRecurrenceKind(Kind))
2731       NewRed = createMinMaxOp(Builder, Kind, NewRed, Prev);
2732     else
2733       NewRed = Builder.CreateBinOp(
2734           (Instruction::BinaryOps)RecurrenceDescriptor::getOpcode(Kind), NewRed,
2735           Prev);
2736   }
2737   State.set(this, NewRed, /*IsScalar*/ true);
2738 }
