2740 InstructionCost VPReductionRecipe::computeCost(ElementCount VF,
2741                                                VPCostContext &Ctx) const {
2742   RecurKind RdxKind = getRecurrenceKind();
2743   Type *ElementTy = Ctx.Types.inferScalarType(this);
2744   auto *VectorTy = cast<VectorType>(toVectorTy(ElementTy, VF));
2745   unsigned Opcode = RecurrenceDescriptor::getOpcode(RdxKind);
2746   FastMathFlags FMFs = getFastMathFlags();
2747   std::optional<FastMathFlags> OptionalFMF =
2748       ElementTy->isFloatingPointTy() ? std::make_optional(FMFs) : std::nullopt;
2749 
2750   if (isPartialReduction()) {
2751     InstructionCost CondCost = 0;
2752     if (isConditional()) {
2753       CmpInst::Predicate Pred = CmpInst::BAD_ICMP_PREDICATE;
2754       auto *CondTy = cast<VectorType>(
2755           toVectorTy(Ctx.Types.inferScalarType(getCondOp()), VF));
2756       CondCost = Ctx.TTI.getCmpSelInstrCost(Instruction::Select, VectorTy,
2757                                             CondTy, Pred, Ctx.CostKind);
2758     }
2759     return CondCost + Ctx.TTI.getPartialReductionCost(
2760                           Opcode, ElementTy, ElementTy, ElementTy, VF,
2761                           TargetTransformInfo::PR_None,
2762                           TargetTransformInfo::PR_None, std::nullopt,
2763                           Ctx.CostKind);
2764   }
2765 
2766   // TODO: Support any-of reductions.
2767   assert(
2768       (!RecurrenceDescriptor::isAnyOfRecurrenceKind(RdxKind) ||
2769        ForceTargetInstructionCost.getNumOccurrences() > 0) &&
2770       "Any-of reduction not implemented in VPlan-based cost model currently.");
2771 
2772   // Note that TTI should model the cost of moving result to the scalar register
2773   // and the BinOp cost in the getMinMaxReductionCost().
2774   if (RecurrenceDescriptor::isMinMaxRecurrenceKind(RdxKind)) {
2775     Intrinsic::ID Id = getMinMaxReductionIntrinsicOp(RdxKind);
2776     return Ctx.TTI.getMinMaxReductionCost(Id, VectorTy, FMFs, Ctx.CostKind);
2777   }
2778 
2779   // Note that TTI should model the cost of moving result to the scalar register
2780   // and the BinOp cost in the getArithmeticReductionCost().
2781   return Ctx.TTI.getArithmeticReductionCost(Opcode, VectorTy, OptionalFMF,
2782                                             Ctx.CostKind);
2783 }
