2040 /// A pure virtual base class for all recipes modeling header phis, including
2041 /// phis for first order recurrences, pointer inductions and reductions. The
2042 /// start value is the first operand of the recipe and the incoming value from
2043 /// the backedge is the second operand.
2044 ///
2045 /// Inductions are modeled using the following sub-classes:
2046 ///  * VPCanonicalIVPHIRecipe: Canonical scalar induction of the vector loop,
2047 ///    starting at a specified value (zero for the main vector loop, the resume
2048 ///    value for the epilogue vector loop) and stepping by 1. The induction
2049 ///    controls exiting of the vector loop by comparing against the vector trip
2050 ///    count. Produces a single scalar PHI for the induction value per
2051 ///    iteration.
2052 ///  * VPWidenIntOrFpInductionRecipe: Generates vector values for integer and
2053 ///    floating point inductions with arbitrary start and step values. Produces
2054 ///    a vector PHI per-part.
2055 ///  * VPDerivedIVRecipe: Converts the canonical IV value to the corresponding
2056 ///    value of an IV with different start and step values. Produces a single
2057 ///    scalar value per iteration
2058 ///  * VPScalarIVStepsRecipe: Generates scalar values per-lane based on a
2059 ///    canonical or derived induction.
2060 ///  * VPWidenPointerInductionRecipe: Generate vector and scalar values for a
2061 ///    pointer induction. Produces either a vector PHI per-part or scalar values
2062 ///    per-lane based on the canonical induction.
2063 class LLVM_ABI_FOR_TEST VPHeaderPHIRecipe : public VPSingleDefRecipe,
2064                                             public VPPhiAccessors {
2065 protected:
2066   VPHeaderPHIRecipe(unsigned char VPDefID, Instruction *UnderlyingInstr,
2067                     VPValue *Start, DebugLoc DL = DebugLoc::getUnknown())
2068       : VPSingleDefRecipe(VPDefID, ArrayRef<VPValue *>({Start}),
2069                           UnderlyingInstr, DL) {}
2070 
2071   const VPRecipeBase *getAsRecipe() const override { return this; }
2072 
2073 public:
2074   ~VPHeaderPHIRecipe() override = default;
2075 
2076   /// Method to support type inquiry through isa, cast, and dyn_cast.
2077   static inline bool classof(const VPRecipeBase *R) {
2078     return R->getVPDefID() >= VPDef::VPFirstHeaderPHISC &&
2079            R->getVPDefID() <= VPDef::VPLastHeaderPHISC;
2080   }
2081   static inline bool classof(const VPValue *V) {
2082     return isa<VPHeaderPHIRecipe>(V->getDefiningRecipe());
2083   }
2084   static inline bool classof(const VPSingleDefRecipe *R) {
2085     return isa<VPHeaderPHIRecipe>(static_cast<const VPRecipeBase *>(R));
2086   }
