2106   /// Returns the incoming value from the loop backedge.
2107   virtual VPValue *getBackedgeValue() {
2108     return getOperand(1);
2109   }
2110 
2111   /// Update the incoming value from the loop backedge.
2112   void setBackedgeValue(VPValue *V) { setOperand(1, V); }
