7829     if (MaskPos.has_value()) {
7830       // We have 2 cases that would require a mask:
7831       //   1) The block needs to be predicated, either due to a conditional
7832       //      in the scalar loop or use of an active lane mask with
7833       //      tail-folding, and we use the appropriate mask for the block.
7834       //   2) No mask is required for the block, but the only available
7835       //      vector variant at this VF requires a mask, so we synthesize an
7836       //      all-true mask.
7837       VPValue *Mask = Legal->isMaskRequired(CI)
7838                           ? getBlockInMask(Builder.getInsertBlock())
7839                           : Plan.getTrue();
7840 
7841       Ops.insert(Ops.begin() + *MaskPos, Mask);
7842     }
7843 
7844     Ops.push_back(VPI->getOperand(VPI->getNumOperands() - 1));
7845     return new VPWidenCallRecipe(CI, Variant, Ops, *VPI, *VPI,
7846                                  VPI->getDebugLoc());
7847   }
7848 
7849   return nullptr;
7850 }
7851 
7852 bool VPRecipeBuilder::shouldWiden(Instruction *I, VFRange &Range) const {
7853   assert(!isa<BranchInst>(I) && !isa<PHINode>(I) && !isa<LoadInst>(I) &&
7854          !isa<StoreInst>(I) && "Instruction should have been handled earlier");
7855   // Instruction should be widened, unless it is scalar after vectorization,
7856   // scalarization is profitable or it is predicated.
7857   auto WillScalarize = [this, I](ElementCount VF) -> bool {
7858     return CM.isScalarAfterVectorization(I, VF) ||
7859            CM.isProfitableToScalarize(I, VF) ||
7860            CM.isScalarWithPredication(I, VF);
7861   };
7862   return !LoopVectorizationPlanner::getDecisionAndClampRange(WillScalarize,
7863                                                              Range);
7864 }
