7866 VPWidenRecipe *VPRecipeBuilder::tryToWiden(VPInstruction *VPI) {
7867   auto *I = VPI->getUnderlyingInstr();
7868   switch (VPI->getOpcode()) {
7869   default:
7870     return nullptr;
7871   case Instruction::SDiv:
7872   case Instruction::UDiv:
7873   case Instruction::SRem:
7874   case Instruction::URem: {
7875     // If not provably safe, use a select to form a safe divisor before widening the
7876     // div/rem operation itself.  Otherwise fall through to general handling below.
7877     if (CM.isPredicatedInst(I)) {
7878       SmallVector<VPValue *> Ops(VPI->operands());
7879       VPValue *Mask = getBlockInMask(Builder.getInsertBlock());
7880       VPValue *One = Plan.getConstantInt(I->getType(), 1u);
7881       auto *SafeRHS =
7882           Builder.createSelect(Mask, Ops[1], One, VPI->getDebugLoc());
7883       Ops[1] = SafeRHS;
7884       return new VPWidenRecipe(*I, Ops, *VPI, *VPI, VPI->getDebugLoc());
7885     }
7886     [[fallthrough]];
7887   }
7888   case Instruction::Add:
7889   case Instruction::And:
7890   case Instruction::AShr:
7891   case Instruction::FAdd:
7892   case Instruction::FCmp:
7893   case Instruction::FDiv:
7894   case Instruction::FMul:
7895   case Instruction::FNeg:
7896   case Instruction::FRem:
7897   case Instruction::FSub:
7898   case Instruction::ICmp:
7899   case Instruction::LShr:
7900   case Instruction::Mul:
7901   case Instruction::Or:
7902   case Instruction::Select:
7903   case Instruction::Shl:
7904   case Instruction::Sub:
7905   case Instruction::Xor:
7906   case Instruction::Freeze:
7907     return new VPWidenRecipe(*I, VPI->operands(), *VPI, *VPI,
7908                              VPI->getDebugLoc());
7909   case Instruction::ExtractValue: {
7910     SmallVector<VPValue *> NewOps(VPI->operands());
7911     auto *EVI = cast<ExtractValueInst>(I);
7912     assert(EVI->getNumIndices() == 1 && "Expected one extractvalue index");
7913     unsigned Idx = EVI->getIndices()[0];
7914     NewOps.push_back(Plan.getConstantInt(32, Idx));
7915     return new VPWidenRecipe(*I, NewOps, *VPI, *VPI, VPI->getDebugLoc());
7916   }
7917   };
7918 }
